	('4318caa2-54b9-41e9-a302-e34f3dd3685e', '[{"role": "주니어 프론트엔드 개발자", "company": "토스", "description": "토스 증권 웹 서비스의 UI 컴포넌트 개발. Vue.js에서 React로의 마이그레이션 프로젝트 참여."}]', '[{"field": "프론트엔드 과정 수료", "degree": "부트캠프", "institution": "멋쟁이사자처럼"}]', '[{"name": "투두리스트 앱 클론코딩", "description": "React와 Redux를 사용하여 Trello와 유사한 칸반보드 스타일의 투두리스트 앱 개발."}]', '{HTML,CSS,JavaScript,React,Vue.js,Redux,Git}', '비전공자 출신으로 멋쟁이사자처럼 부트캠프를 통해 프론트엔드 개발에 입문했으며, 현재는 토스에서 React를 사용하여 복잡한 금융 서비스의 사용자 인터페이스를 개발하고 있습니다.', '[-0.061806552,-0.036194783,-0.02864788,0.010420367,0.011754088,-0.004960789,-0.039165836,0.06323786,0.017631132,-0.050616313,0.019116657,-0.0237901,0.038428493,0.041529663,0.021545546,0.022575656,-0.012480586,-0.013879365,-0.08357981,0.012122759,-0.041703157,-0.039361015,0.021968434,-0.0017145897,0.011276985,0.033896014,-0.029949069,0.009303512,-0.019311836,-0.0062728226,-0.0065655904,-0.01906244,0.030946648,0.04584528,0.034004446,-0.039165836,-0.011439634,0.050356075,0.016611867,0.033787582,-0.009260139,-0.024505755,-0.03205266,0.03218278,-0.027910536,0.0063758334,-0.032529764,0.032724943,0.037387542,-0.0089077335,-0.026370795,0.024549128,0.045194685,-0.023659982,0.0101872375,-0.0013628616,0.02485274,-0.009704713,-0.01885642,0.062413774,0.056298178,0.005660179,-0.013510695,0.0023001253,-0.025264783,0.00942821,-0.024679247,0.03571768,-0.037387542,0.037409227,0.013489009,-0.015766092,0.0048360913,0.012968533,0.038189944,-0.008766771,0.03675863,0.04987897,0.004716816,-0.048924763,0.00399845,-0.04205014,-0.021708196,-0.013282986,-0.013543225,-0.0063053523,-0.03218278,-0.031532183,-0.025264783,0.0010307869,-0.012708294,0.054129526,-0.004920127,-0.008376414,0.028127402,0.037365854,0.018780516,0.012144445,0.04970548,0.046669368,0.026847899,-0.047493454,0.0091517065,-0.04250556,0.048794646,0.0070047425,0.009048696,0.008750507,-0.0120902285,0.035067085,-0.023117818,0.053045202,-0.028149089,-0.019474486,-0.022315418,-0.06497278,0.03803814,-0.015473324,-0.015635973,-0.027216569,-0.026674407,0.