	('89fb1ae8-ef2a-4d45-bd02-00ad576c58d2', '[{"role": "데이터 엔지니어", "company": "마켓컬리", "description": "Airflow와 Spark를 사용한 데이터 파이프라인 구축 및 관리. 데이터 웨어하우스(Redshift) 설계 및 운영."}]', '[{"field": "학사", "degree": "산업경영공학부", "institution": "고려대학교"}]', '[{"name": "로그 수집 시스템", "description": "Fluentd, Kafka, Elasticsearch를 사용하여 대용량 로그 데이터를 수집하고 분석하는 시스템을 구축."}]', '{Python,SQL,Airflow,Spark,Kafka,"AWS Redshift","Data Warehouse"}', '산업공학을 전공하고 데이터 분야에 뛰어들었으며, 현재는 마켓컬리에서 Airflow와 Spark를 사용하여 대용량 데이터를 처리하고 분석가들이 사용할 수 있도록 데이터 웨어하우스를 구축하는 데이터 엔지니어입니다.', '[0.012327711,-0.015053027,0.0015061726,-0.024840975,0.06049044,0.0008821039,-0.061557375,0.0407058,-0.010564952,-0.02609346,-0.018845277,-0.009689372,-0.024307508,0.010066277,0.0032326898,0.011759453,-0.017685568,0.010669326,-0.028018579,0.01708252,0.005949309,0.025049722,0.029039122,-0.028088162,-0.036206126,0.00407058,0.03938373,0.06373763,0.0023730553,-0.065361224,0.019262772,-0.023646474,0.0051694047,0.029015929,0.014995042,-0.032495055,-0.002199099,-0.0004345286,0.031660065,-0.0021759048,-0.011098418,0.0040763784,0.010518564,0.038525544,0.054923836,0.025235277,-0.062067647,0.0038560338,0.06350569,0.023669668,-0.03295894,0.011295569,0.011776849,-0.049125288,-0.0064653796,0.034141842,0.009985098,-0.021582192,-0.011237584,-0.017824734,0.071159765,-0.0038096453,0.02442348,0.009909716,-0.020897962,0.024632227,-0.014009289,0.036020573,-0.04620282,0.006587149,0.0046794275,-0.032541446,-0.0065059694,-0.020955948,-0.005311469,-0.043233965,-0.012722012,0.010506967,-0.038571935,-0.016978145,-0.013858527,2.3579247e-05,-0.011457928,-0.014937057,0.005682576,-0.05538772,-0.0118464315,-0.023136202,-0.03384032,-0.034698505,-0.014635532,0.06132543,-8.68423e-05,-0.04026511,0.0034211427,0.029433424,0.029665366,-0.0031254168,0.040752187,0.025884714,-0.0022846274,-0.022776691,0.040149137,-0.009637185,0.007538111,-0.009254481,-0.057289645,-0.021582192,-0.035371136,-0.016166348,-0.050377775,0.00674371,0.012107366,-0.021280667,-0.017615985,0.0039053212,0.