	('a8fd5644-70f8-49c4-a10e-57903443f462', '[{"role": "CTO (최고기술책임자)", "company": "개인 창업 스타트업", "description": "AI 기반 교육 서비스의 기술 전략 수립, 팀 빌딩, 초기 프로토타입 개발(Python, React) 주도."}, {"role": "시니어 백엔드 개발자", "company": "쿠팡", "description": "쿠팡의 검색 및 추천 시스템 고도화 프로젝트 리드."}]', '[{"field": "석사", "degree": "컴퓨터공학과", "institution": "POSTECH"}]', '[{"name": "오픈소스 기여 다수", "description": "Apache Spark, Kafka 등 유명 오픈소스 프로젝트에 코드 기여."}]', '{Leadership,Architecture,Python,Go,React,AWS,Kubernetes,AI/ML}', '포항공대 컴퓨터공학 석사 졸업 후 쿠팡에서 시니어 개발자로 대규모 시스템을 경험했으며, 현재는 AI 교육 스타트업을 창업하여 기술 비전 수립과 개발 팀을 이끌고 있는 CTO입니다.', '[-0.032709304,-0.05140935,0.0013606965,-0.0125368135,0.008860961,-0.0031973082,0.03798907,0.09692892,-0.01470341,-0.06503998,0.023033239,-0.027492642,0.0036048596,-0.008240431,-0.016386203,0.015439632,-0.06920489,-0.009954777,0.029953727,-0.020856125,-0.0034234335,-0.013062687,0.007924907,0.019120743,0.024884311,-0.016722763,0.04745478,0.016817419,-0.046150617,-0.027660921,0.046613384,-0.012589401,-0.016933111,0.0069941115,0.004609277,-0.015723603,0.0039414186,0.00517722,0.039082885,-0.01201094,-0.013925118,-0.028313003,0.01068574,0.028144725,0.006694364,-0.033676907,-0.00034871956,0.019204883,-0.006357805,0.013609594,-0.016102232,0.050988648,0.031741697,0.004759151,-0.0052087726,0.028439214,-0.018174171,-0.018352969,-0.01822676,0.009034499,-0.008813632,0.03085823,0.012358016,0.008040599,-0.009271142,-0.03956669,-0.0039940057,0.055153564,-0.049852762,0.023054274,-0.0023191,0.002397981,0.008776821,0.026419861,0.017606229,-0.04833825,0.005377052,0.052713513,0.012820785,0.0019667652,-0.025031557,-0.0715608,0.022381157,-0.04901137,-0.021013886,-0.030458566,-0.054228026,-0.0410812,-0.0070151463,-0.031426173,0.019173332,0.0560791,-0.017332776,-0.01826883,0.027576782,-0.014272194,0.022970134,0.032856546,0.044341613,-0.003483909,-0.019310057,0.0041070683,0.01942575,0.019173332,-0.01420909,0.03872529,-0.0128102675,-0.02846025,-0.0006790336,0.011421963,-0.043962985,-0.011916283,-0.0039124954,0.