	('18703256-25dd-4c28-a531-33074fd1fd1c', '[{"role": "프로덕트 매니저 (PM)", "company": "배달의민족", "description": "배민라이더스 서비스의 신규 기능 기획, 사용자 스토리 작성, 개발팀과 협업하여 제품 출시."}, {"role": "서비스 기획자", "company": "야놀자", "description": "숙소 예약 서비스의 사용자 리서치 및 화면 설계."}]', '[{"field": "학사", "degree": "경영학과", "institution": "서강대학교"}]', '[{"name": "대학생 시간표 앱 기획", "description": "Figma를 사용하여 대학생들을 위한 소셜 시간표 앱의 프로토타입 제작 및 사용자 테스트 진행."}]', '{"Product Management",Agile,Scrum,JIRA,Figma,"Data Analysis",SQL}', '경영학을 전공하고 서비스 기획자로 커리어를 시작했으며, 현재는 배달의민족에서 데이터를 기반으로 사용자의 문제를 정의하고 개발팀과 긴밀하게 협력하여 제품을 만들어가는 프로덕트 매니저(PM)입니다.', '[0.031931538,0.025665963,0.025291277,-0.0148937525,0.032472752,0.0104391575,0.015029056,0.08118188,-0.030828299,-0.009486831,0.028996501,-0.057202,0.008945619,-0.009554483,0.036448583,-0.03359681,-0.048292812,-0.03619879,-0.0333262,0.020566076,0.06344676,0.0127289025,0.033804968,-0.01218769,0.012812166,0.040008094,-0.00034703952,0.037947323,-0.020795051,-0.06465408,-0.0137905115,-0.025811674,-0.020285062,-0.009486831,0.04229784,-0.055786524,0.025270462,-0.0016470554,0.036282055,0.021919107,-0.021960739,-0.045253694,0.025853306,0.034720864,0.027518576,-0.0029974848,-0.013988262,0.02905895,0.059408482,0.03873833,-0.006078233,0.011969123,0.04467085,0.0027216745,0.03701061,0.028434474,0.073438376,0.031473592,-0.03172338,0.014196421,0.052664142,-0.0046159183,-0.027789181,0.008701032,-0.017152274,-0.013030732,-0.022710111,0.0010895805,-0.048126284,0.0141443815,-0.0031640118,0.0107097635,-0.0066090375,-0.042464368,0.021773396,-0.014529475,0.017860014,0.0096273385,-0.030474428,-0.029891584,0.006078233,-0.0123125855,0.016777588,-0.03540779,-0.036635924,-0.026623493,-0.02810142,-0.02533291,-0.0069004595,-0.017995317,-0.03651103,0.049167078,-0.026311256,0.0021258204,0.008706236,0.0068171965,0.0064789383,0.07318859,0.04608633,0.03615716,0.0017407269,-0.036760822,0.00066253,-7.175782e-05,-0.016673509,-0.017662263,-0.02246032,0.011760965,-0.043671686,0.00084889703,-0.03470005,-0.006671485,0.024437