	('e02b8954-39ab-4bd0-ae40-e0d0281acc29', '[{"role": "UX/UI 디자이너", "company": "뱅크샐러드", "description": "자산 관리 앱의 사용자 리서치, 정보 구조 설계(IA), 와이어프레임 및 프로토타입 제작. 디자인 시스템 관리."}]', '[{"field": "학사", "degree": "시각디자인과", "institution": "국민대학교"}]', '[{"name": "디자인 시스템 스터디", "description": "Figma의 Variants, Auto Layout 기능을 깊이 있게 학습하고 개인 디자인 시스템 구축."}]', '{"UX Research","UI Design",Prototyping,Figma,Sketch,"Adobe XD","Design System"}', '시각디자인을 전공한 UX/UI 디자이너로, 사용자에 대한 깊은 이해를 바탕으로 복잡한 금융 정보를 쉽고 편리하게 보여주는 인터페이스를 설계합니다. 현재 뱅크샐러드에서 디자인 시스템을 구축하고 운영하고 있습니다.', '[-0.0324925,-0.010744532,-0.04552402,0.020874165,0.02642982,-0.00039543596,-0.019083409,0.061317183,0.0024515006,-0.033679143,-0.0048032156,-0.0022317017,-0.011650696,0.004992,0.026926054,0.028328452,-0.033528116,-0.049493887,-0.040194903,0.009865335,0.0059925574,-0.040475383,0.06584801,-0.0005862431,0.033614416,0.005830742,-0.003837718,-0.024121257,-0.013042307,-0.030054482,-0.001001906,-0.03173736,0.01991406,-0.007599922,0.03801579,0.003832324,-0.006046496,0.025760984,0.054758273,0.022179475,-0.026818177,-0.0077563436,0.0041181976,-0.0032983338,0.03872778,0.0050648167,0.0071522333,0.042093534,0.012438198,0.025027422,-0.059548005,0.011834087,-0.0036893873,0.0036246611,-0.012621588,0.027810644,0.007567559,-0.045221962,-0.0011414716,0.04062641,0.051780872,5.4149106e-05,0.021327248,0.008322696,-0.045265112,-0.0054100226,-0.016958237,0.01419659,-0.05398156,-0.008220213,0.05436992,-0.012319533,-9.8690434e-05,-0.017422106,0.0076808296,-0.022136323,0.0096549755,0.034714762,0.044661004,0.01377587,0.034412704,-0.0075459834,-0.03648394,-0.01647279,-0.028522631,-0.036419213,-0.017184777,0.045351416,-0.03298873,-0.01866269,-0.046041828,0.039763395,-0.040043876,-0.020302417,-0.01349539,0.05208293,-0.008673296,0.040928464,0.019558068,0.052471284,0.07767131,-0.05458567,0.0068987226,-0.040971614,0.020485807,-0.07728295,0.0096765505,0.0039536855,-0.0413384,-0.022093173,-0.036742844,0.038555175,0.002455546,-0.025437355,-0.001916162,-0.02839318,0.