	('8d9279c1-b8f4-49c9-a437-01e9f3fba340', '[{"role": "Go 개발자", "company": "토스", "description": "토스페이먼츠의 결제 게이트웨이 서버 개발. Go 언어를 사용하여 높은 동시성과 안정성을 갖춘 API 서버 구축."}]', '[{"field": "학사", "degree": "전기전자컴퓨터공학부", "institution": "광주과학기술원(GIST)"}]', '[{"name": "분산 키-값 저장소", "description": "Raft 합의 알고리즘을 Go로 구현하여 간단한 분산 키-값 저장소(Key-Value Store) 개발."}]', '{Go,gRPC,Microservices,Concurrency,PostgreSQL,Kubernetes,Docker}', 'Go 언어의 동시성 모델과 성능에 매료되어 집중적으로 파고든 백엔드 개발자입니다. 현재 토스에서 마이크로서비스 아키텍처 기반의 안정적이고 빠른 결제 서버를 Go로 개발하고 있습니다.', '[0.032636717,-0.0132225575,0.019621272,0.008671512,0.010966111,0.011620154,-0.03980938,0.047527082,0.01571882,-0.081406474,0.015849628,-0.014454337,-0.032527708,-0.015522607,0.0011970338,-0.024919016,-0.02746978,-0.037847254,-0.008137378,-0.038850117,-0.009696178,-0.0048044864,0.029322902,0.0136912875,-0.00059068203,0.006431417,-0.019523166,-0.008164629,0.0006489327,-0.08899337,-0.00910209,-0.029889738,0.044213265,0.010273916,0.00023640908,-0.02655412,0.022782477,0.02330571,-0.03318175,0.0057446724,-0.031067014,0.003886102,-0.008426246,0.03959137,-0.007341626,0.04395165,0.031241424,-0.014279925,-0.0060498924,0.033072744,-0.034686048,0.043297607,0.022542661,0.007003704,0.008371742,0.0030630985,0.027993014,0.0027728672,0.0447365,0.042054925,0.006431417,0.0021324507,-0.05014325,0.02207393,-0.014639649,-0.020460626,0.00041933655,0.02204123,-0.06588387,0.058078963,-0.023850746,-0.028080221,-0.017223116,-0.022935087,-0.029344702,-0.059823077,0.0045455946,0.04375544,0.054808754,0.009134792,-0.016122146,-0.015969535,-0.025921881,-0.021060165,0.024417583,-0.05336986,-0.043515623,-0.03344337,-0.040855847,0.06714835,-0.013364267,0.02391615,0.009728881,0.02328391,0.0016064916,0.02823283,-0.022270143,0.015773322,0.008851374,0.07216268,0.032484107,-0.03163385,-0.017615542,-0.061174765,0.03363958,-0.021605201,0.00955992,-0.0066221794,-0.069372095,0.04207673,-0.012939138,0.0032811128,-0.029998744,-0.051669348,-0.016710782,0.018836422,-0.008922229,0.015697017,0.010404725,-