INSERT INTO "public"."plans" ("id", "title", "description", "objective", "context", "plan_structure", "metadata", "plan_source", "generated_at", "created_at", "updated_at") VALUES
	('02e0a269-7a83-4bdb-b2e9-bbcf60bbd048', 'Mobile App Development Strategy', 'Comprehensive plan for developing a mobile fitness tracking application with social features', 'Launch a successful mobile app that helps users track fitness goals and connect with others', '{"keywords": ["mobile", "app", "fitness", "social", "tracking"], "user_input": "I want to create a mobile app for tracking fitness goals with social features", "enterprise_data_sources": ["internal_wiki", "tech_standards"]}', '[{"id": "research_phase", "type": "goal", "title": "Market Research and Planning", "status": "pending", "children": [{"id": "competitor_analysis", "type": "task", "title": "Competitor Analysis", "status": "pending", "metadata": {"tags": ["analysis"], "complexity": 2, "risk_level": 1, "effort_level": 2, "skills_required": ["competitive_analysis"], "resources_required": ["researcher"]}, "priority": "high", "timeline": {"estimated_duration": "1 week"}, "description": "Analyze existing fitness apps and identify opportunities"}], "metadata": {"tags": ["research", "planning"], "complexity": 2, "risk_level": 1, "effort_level": 3, "skills_required": ["market_research", "user_analysis"], "resources_required": ["product_manager", "researcher"]}, "priority": "high", "timeline": {"estimated_duration": "2 weeks"}, "description": "Research target audience, competitors, and technical requirements"}, {"id": "development_phase", "type": "goal", "title": "App Development", "status": "pending", "metadata": {"tags": ["development", "critical_path"], "complexity": 4, "risk_level": 3, "effort_level": 5, "skills_required": ["React Native", "Node.js", "UI/UX Design"], "resources_required": ["mobile_developer", "ui_designer", "backend_developer"]}, "priority": "critical", "timeline": {"dependencies": ["research_phase"], "estimated_duration": "8 weeks"}, "description": "Design and implement the mobile application"}]', '{"risk_assessment": "Medium risk due to technical complexity and market competition", "success_metrics": ["App launched on both iOS and Android", "1000+ active users within first month", "4.0+ star rating in app stores", "Social features engagement >50%"], "complexity_score": 7, "confidence_score": 8, "total_estimated_duration": "10 weeks"}', 'openai', '2025-08-10 08:47:24.225851+00', '2025-08-10 08:47:24.225851+00', '2025-08-10 08:47:24.225851+00'),
	('c41eaac3-55b4-4d59-bd9e-7079ba3d8ba8', 'Enterprise Automation Implementation', 'Plan to implement workflow automation across business units', 'Reduce manual processes by 60% and improve operational efficiency', '{"keywords": ["automation", "workflow", "efficiency", "enterprise"], "user_input": "We need to automate our business processes to improve efficiency", "enterprise_data_sources": ["internal_wiki", "process_docs"]}', '[{"id": "process_audit", "type": "goal", "title": "Current Process Audit", "status": "pending", "metadata": {"tags": ["audit", "analysis"], "complexity": 3, "risk_level": 2, "effort_level": 4, "skills_required": ["process_mapping", "workflow_analysis"], "resources_required": ["process_analyst", "department_leads"]}, "priority": "high", "timeline": {"estimated_duration": "3 weeks"}, "description": "Assess existing workflows and identify automation opportunities"}, {"id": "automation_implementation", "type": "goal", "title": "Automation Tool Implementation", "status": "pending", "metadata": {"tags": ["implementation", "automation"], "complexity": 4, "risk_level": 3, "effort_level": 5, "skills_required": ["RPA", "system_integration", "change_management"], "resources_required": ["automation_engineer", "system_administrator"]}, "priority": "critical", "timeline": {"dependencies": ["process_audit"], "estimated_duration": "6 weeks"}, "description": "Deploy and configure automation solutions"}]', '{"risk_assessment": "Medium-high risk due to change management challenges", "success_metrics": ["60% reduction in manual process time", "90% automation accuracy rate", "Employee satisfaction score >7/10", "ROI positive within 6 months"], "complexity_score": 8, "confidence_score": 7, "total_estimated_duration": "12 weeks"}', 'openai', '2025-08-10 08:47:24.225851+00', '2025-08-10 08:47:24.225851+00', '2025-08-10 08:47:24.225851+00');
