INSERT INTO "public"."processed_inputs" ("id", "raw_text", "keywords", "processed_at", "created_at") VALUES
	(1, 'ㅁㄴㅇㅁㄴㅇ', '{"nouns": ["ㅁㄴㅇㅁㄴㅇ"], "verbs": [], "entities": []}', '2025-08-10 10:52:31.41+00', '2025-08-10 10:52:31.423213+00'),
	(2, '휴대폰 로그인도 꼭 필요하다면 (SMS 활성화) 로컬에선 기본 비활성화라 경고가 뜨는 거야. 쓰려면 supabase/config.toml의 Auth 설정을 열고 SMS 제공자와 자격증명(Twilio 등)을 채워야 해.', '{"nouns": ["휴대폰", "로그인도", "필요하다면", "(SMS", "활성화)", "로컬에선", "기본", "비활성화라", "경고가", "뜨는", "거야.", "쓰려면", "supabase/config.toml의", "Auth", "설정을", "열고", "SMS", "제공자와", "자격증명(Twilio", "등)을", "채워야", "해."], "verbs": [], "entities": []}', '2025-08-10 10:53:06.026+00', '2025-08-10 10:53:06.044427+00'),
	(3, '흔한 문제 빠르게 해결 Docker가 꺼져 있거나 리소스 부족 → Docker 실행, 메모리 4–6GB 이상 할당.  컨테이너 충돌/잔여 리소스 → supabase stop 후 다시 supabase start. 그래도 안 되면 Docker에서 해당 컨테이너 중지/삭제 후 재시작.  권한/네트워크 이슈(Windows) → PowerShell/터미널을 관리자 권한으로 실행, WSL 네트워크 재시작.', '{"nouns": ["흔한", "문제", "빠르게", "해결", "Docker가", "꺼져", "있거나", "리소스", "부족", "Docker", "실행,", "메모리", "4–6GB", "이상", "할당.", "컨테이너", "충돌/잔여", "리소스", "supabase", "stop", "다시", "supabase", "start.", "그래도", "되면", "Docker에서", "해당", "컨테이너", "중지/삭제", "재시작.", "권한/네트워크", "이슈(Windows)", "PowerShell/터미널을", "관리자", "권한으로", "실행,", "WSL", "네트워크", "재시작."], "verbs": [], "entities": []}', '2025-08-10 11:17:31.105+00', '2025-08-10 11:17:31.124203+00'),
	(4, 'ㅁㄴㅇㄹㅁㄴㄹㅇ', '{"nouns": ["ㅁㄴㅇㄹㅁㄴㄹㅇ"], "verbs": [], "entities": []}', '2025-08-10 11:52:51.632+00', '2025-08-10 11:52:51.66195+00'),
	(5, 'LLM 프롬프트 구성 예(요지) 입력: 사용자 목표(career_targets), 상위 유사 조각(career_chunks 10~20개), 요약 메타(경력 연차/산업/지역), 갭 분석 규칙(필수/가산 스킬, 최근성 가중치).  출력: ① 갭 리스트(근거 조각 ID 포함), ② 우선순위 로드맵(주/월 단위), ③ 추천 학습/프로젝트, ④ 예상 이직 포지션.  결론 Yes: 현재 테이블만으로도 기본 RAG는 잘 돌아갑니다.  Better: 위 4가지를 추가하면 개인화된 커리어 설계 품질이 눈에 띄게 좋아집니다(조각 단위 임베딩, 하이브리드 검색, 목표/제약 저장, 숙련도/최근성 메타).  원하면 제가 career_chunks를 JSONB에서 자동 생성하는 SQL/함수와, Supabase Edge Function으로 임베딩 갱신 파이프라인까지 바로 잡아드릴게요.', '{"nouns": ["LLM", "프롬프트", "구성", "예(요지)", "입력:", "사용자", "목표(career_targets),", "상위", "유사", "조각(career_chunks", "10~20개),", "요약", "메타(경력", "연차/산업/지역),", "분석", "규칙(필수/가산", "스킬,", "최근성", "가중치).", "출력:", "리스트(근거", "조각", "ID", "포함),", "우선순위", "로드맵(주/월", "단위),", "추천", "학습/프로젝트,", "예상", "이직", "포지션.", "결론", "Yes:", "현재", "테이블만으로도", "기본", "RAG는", "돌아갑니다.", "Better:", "4가지를", "추가하면", "개인화된", "커리어", "설계", "품질이", "눈에", "띄게", "좋아집니다(조각", "단위", "임베딩,", "하이브리드", "검색,", "목표/제약", "저장,", "숙련도/최근성", "메타).", "원하면", "제가", "career_chunks를", "JSONB에서", "자동", "생성하는", "SQL/함수와,", "Supabase", "Edge", "Function으로", "임베딩", "갱신", "파이프라인까지", "바로", "잡아드릴게요."], "verbs": [], "entities": []}', '2025-08-10 12:20:37.357+00', '2025-08-10 12:20:37.374795+00'),
	(6, '숭실대 소프트웨어학부 4학년으로, 4D AI 에이전트·VTON(3DGS) 등 프로젝트 경험을 바탕으로 PyTorch·Unity·React·TypeScript·Python·Node.js·Supabase·Docker·AWS를 다루며 음성·3D·RAG 시스템을 빠르게 프로토타입한 경험(교내/해커톤 입상 포함)이 있습니다.', '{"nouns": ["숭실대", "소프트웨어학부", "4학년으로,", "4D", "AI", "에이전트·VTON(3DGS)", "프로젝트", "경험을", "바탕으로", "PyTorch·Unity·React·TypeScript·Python·Node.js·Supabase·Docker·AWS를", "다루며", "음성·3D·RAG", "시스템을", "빠르게", "프로토타입한", "경험(교내/해커톤", "입상", "포함)이", "있습니다."], "verbs": [], "entities": []}', '2025-08-10 12:52:15.236+00', '2025-08-10 12:52:15.269213+00'),
