	('c76bba6e-29aa-4ca6-a7f8-454fba45326c', 'I want to create a mobile app for tracking fitness goals and workouts. The app should have user authentication, progress tracking, and social features.', '{"nouns": ["app", "fitness", "goals", "workouts", "authentication", "progress", "tracking", "features"], "verbs": ["create", "tracking", "have"], "topics": ["mobile app", "fitness goals", "user authentication", "progress tracking", "social features"], "entities": [], "sentiment": "positive", "adjectives": ["mobile", "social"]}', '2025-08-10 08:47:24.011574+00', '2025-08-10 08:47:24.011574+00', '2025-08-10 08:47:24.011574+00'),
	('14d43b94-90a7-4ef8-935b-329dc2507791', 'The current system is slow and difficult to use. We need better performance and a more intuitive user interface design.', '{"nouns": ["system", "performance", "interface", "design"], "verbs": ["need", "use"], "topics": ["current system", "user interface", "interface design"], "entities": [], "sentiment": "negative", "adjectives": ["slow", "difficult", "better", "intuitive"]}', '2025-08-10 08:47:24.011574+00', '2025-08-10 08:47:24.011574+00', '2025-08-10 08:47:24.011574+00');
